head.script:
scwin.lobranCd       = $c.data.getMemInfo("lobranCd");// 물류 점소 코드

scwin.strCurDate = WebSquare.date.getCurrentServerDate();  // 서버를 기준으로 현재 날짜 반환
scwin.vwrkStDt = scwin.strCurDate.substring(0, 6) + "01";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
scwin.vwrkEndDt = scwin.strCurDate.substring(0, 6);  // 입항예정일자 to(현재 날짜가 포함된 달의 마지막 일자)

scwin.v_workClsCd = ""; 
scwin.bOnPopUp = false;



scwin.onpageload = function() {
    scwin.f_initSetTab(); //tab세팅	
	scwin.f_SetDefaultData();
    gr_eqMan.setColumnVisible("workDt", false);


    const codeOptions = [

        { grpCd : "OP117", compID : "gr_payDetail:shiftClsCd"}                   
    ];
    $c.data.setCommonCode(codeOptions);
    tac_tabControl1.activateTab(1);
};

scwin.f_gridToExcel = async function (argGrid, argTitle) {

    // 검색조건
  var totCnt = ds_eqMan.getRowCount();
   var colCnt = 0;
    if( totCnt != "0"){
        var cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
        if (cfrm){
            var checkSub = "false";
            if (chb_dailygb.getValue() == 1) {
                checkSub = "true";
                colCnt = 15;
            } else {
                colCnt = 10;
            }
            const options = {
                fileName: "급여집계(장비).xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
                sheetName: "급여집계(장비)",
                startRowIndex: 2,
                startColumnIndex: 0,
                useSubTotal : checkSub
            };

        // 타이틀
            const infoArr = [{
                rowIndex: 0, colIndex: 0, rowSpan: 1, colSpan: colCnt, text: "급여집계(장비)", textAlign: "center",
                drawBorder: false, fontSize: "18px"
            }];

            $c.data.downloadGridViewExcel(gr_eqMan, options, infoArr);
        }
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);    
    }
};


